/// <summary>
/// Export The Suspension of FD value
/// </summary>
Public class ETGSuspensionofFdvalueExport  extends RunBaseBatch
{
    #define.filename("Suspension of FD value")
    DialogGroup              dlgUploadGroup;
    Dialog                   dialog;

    #define.CurrentVersion(3)
    #localmacro.CurrentList
    prodMCNumber
    #endmacro

}

Method.Source:
public Object dialog()
{
    dialog = super();
    dlgUploadGroup   = dialog.addGroup('Suspension of FD value');

    return dialog;
}

public boolean getFromDialog()
{
    boolean ret;

    ret = super();

    return ret;
}

public container pack()
{
    container ret;

    ret = super();

    return ret;
}

public boolean unpack(container packedClass)
{
    boolean ret;

    ret = super(packedClass);

    return ret;
}

public static ClassDescription description()
{
    return "Suspension of FD value";
}

public void run()
{
    if (ETGACFParameters::find().EnableContractFDAutomation)
    {

        DimensionAttributeValue         dimensionAttributeValue;
        DimensionFinancialTag           dimensionFinancialTag;
        Name                            name;
        RecId                           financialTagCategory;
        ETGACFParameters                acfParameters         = ETGACFParameters::find();
        DimensionAttribute              dimensionAttribute    = DimensionAttribute::findByName(acfParameters.Contract);

        System.IO.MemoryStream memoryStream = new System.IO.MemoryStream();
        using (var package = new OfficeOpenXml.ExcelPackage(memoryStream))
        {
            var currentRow = 1;
            var worksheets = package.get_Workbook().get_Worksheets();
            var DimensionValueWorksheet = worksheets.Add("GLExport");
            var cells = DimensionValueWorksheet.get_Cells();

            OfficeOpenXml.ExcelRange cell = cells.get_Item(currentRow, 1);
            System.String value = "DimensionValue";
            cell.set_Value(value);
            var column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
            var columnStyle = column.get_Style();
            var columnNumberFormat =  columnStyle.get_Numberformat();
            columnNumberFormat.set_Format("@");

            cell = null;
            value = "Description";
            cell = cells.get_Item(currentRow, 2);
            cell.set_Value(value);
            column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
            columnStyle = column.get_Style();
            columnNumberFormat =  columnStyle.get_Numberformat();
            columnNumberFormat.set_Format("@");


            cell = null;
            value = "ActiveFrom";
            cell = cells.get_Item(currentRow, 3);
            cell.set_Value(value);
            column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
            columnStyle = column.get_Style();
            columnNumberFormat =  columnStyle.get_Numberformat();
            columnNumberFormat.set_Format("@");


            cell = null;
            value = "ActiveTo";
            cell = cells.get_Item(currentRow, 4);
            cell.set_Value(value);
            column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
            columnStyle = column.get_Style();
            columnNumberFormat =  columnStyle.get_Numberformat();
            columnNumberFormat.set_Format("@");

            cell = null;
            value = "IsSuspended";
            cell = cells.get_Item(currentRow, 5);
            cell.set_Value(value);
            column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
            columnStyle = column.get_Style();
            columnNumberFormat =  columnStyle.get_Numberformat();
            columnNumberFormat.set_Format("@");

            while select dimensionAttributeValue
                  where dimensionAttributeValue.DimensionAttribute == dimensionAttribute.RecId
            {

                select firstonly dimensionFinancialTag where dimensionFinancialTag.RecId == dimensionAttributeValue.EntityInstance;

                currentRow++;

                cell  = null;
                value = dimensionFinancialTag.Value;
                cell  = cells.get_Item(currentRow, 1);
                cell.set_Value(value);

                cell  = null;
                value = dimensionFinancialTag.Description;
                cell  = cells.get_Item(currentRow, 2);
                cell.set_Value(value);

                cell  = null;
                value =  date2Str(dimensionAttributeValue.ActiveFrom, 213, 02, DateSeparator::Hyphen, 02, DateSeparator::Hyphen, 04);
                cell  = cells.get_Item(currentRow, 3);
                cell.set_Value(value);

                cell  = null;
                value =  date2Str(dimensionAttributeValue.ActiveTo, 213, 02, DateSeparator::Hyphen, 02, DateSeparator::Hyphen, 04);
                cell  = cells.get_Item(currentRow, 4);
                cell.set_Value(value);


                str enumValue = Enum2Str(dimensionAttributeValue.IsSuspended);
                cell  = null;
                value = enumValue;
                cell  = cells.get_Item(currentRow, 5);
                cell.set_Value(value);

            }

            package.Save();
            file::SendFileToUser(memoryStream, "Suspension of FD value.xlsx");

        }
    }
}

public static void main(Args _args)
{
    ETGSuspensionofFdvalueExport   Export = new ETGSuspensionofFdvalueExport();

    if(Export.prompt())
    {
        Export.runOperation();
    }

}
